package com.hospital.management.filter;
import org.junit.jupiter.api.Test;import javax.servlet.FilterChain;import javax.servlet.http.*;import static org.mockito.Mockito.*;
class CsrfFilterTest {@Test void validContinues()throws Exception{HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);HttpSession s=mock(HttpSession.class);FilterChain c=mock(FilterChain.class);when(q.getMethod()).thenReturn("POST");when(q.getRequestURI()).thenReturn("/login");when(q.getContextPath()).thenReturn("");when(q.getSession(false)).thenReturn(s);when(s.getAttribute("csrfToken")).thenReturn("abc");when(q.getParameter("csrfToken")).thenReturn("abc");new CsrfFilter().doFilter(q,r,c);verify(c).doFilter(q,r);}@Test void missingDenied()throws Exception{HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);when(q.getMethod()).thenReturn("POST");when(q.getRequestURI()).thenReturn("/logout");when(q.getContextPath()).thenReturn("");new CsrfFilter().doFilter(q,r,mock(FilterChain.class));verify(r).sendError(403);}}
